import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:5000/api/reviews";

const AdminReviews = () => {
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [replyText, setReplyText] = useState("");
  const [activeReview, setActiveReview] = useState(null);

  useEffect(() => {
    fetchReviews();
  }, []);

  const fetchReviews = async () => {
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5000/api/products");
      let allReviews = [];

      for (const p of res.data.products || []) {
        const rv = await axios.get(`${API_BASE}/${p._id}`);
        if (rv.data.data.length > 0) {
          allReviews.push(
            ...rv.data.data.map((r) => ({ ...r, productName: p.name }))
          );
        }
      }
      setReviews(allReviews);
    } catch (err) {
      console.error("❌ Lỗi lấy đánh giá:", err);
    }
    setLoading(false);
  };

  const submitReply = async () => {
    if (!activeReview) return;

    try {
      await axios.put(
        `${API_BASE}/${activeReview._id}/reply`,
        { reply: replyText },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      alert("✔ Phản hồi thành công!");
      setReplyText("");
      setActiveReview(null);
      fetchReviews();
    } catch (err) {
      console.error("❌ Lỗi reply:", err);
      alert("Không thể phản hồi.");
    }
  };

  if (loading)
    return (
      <div className="text-center mt-20 text-pink-600 text-xl">
        Đang tải đánh giá...
      </div>
    );

  return (
    <div className="p-6 bg-white rounded-xl shadow max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-[#4b2c35] mb-6">
        📋 Quản lý đánh giá sản phẩm
      </h2>

      {reviews.length === 0 && (
        <p className="text-gray-500">Chưa có đánh giá nào.</p>
      )}

      <div className="space-y-5">
        {reviews.map((rv) => (
          <div
            key={rv._id}
            className="border p-4 rounded-lg shadow-sm bg-pink-50"
          >
            <div className="flex justify-between items-center">
              <p className="font-semibold">
                {rv.user?.name} •{" "}
                <span className="text-yellow-600">{rv.rating}★</span>
              </p>
              <p className="text-sm text-gray-600">{rv.productName}</p>
            </div>

            <p className="mt-1 text-gray-700">{rv.comment}</p>

            {rv.adminReply && (
              <div className="mt-2 p-3 bg-white border-l-4 border-pink-300 rounded">
                <p className="font-medium text-pink-700 mb-1">Phản hồi:</p>
                <p>{rv.adminReply}</p>
              </div>
            )}

            {/* Nút trả lời */}
            <button
              className="mt-3 px-4 py-1 bg-pink-600 text-white rounded-full hover:bg-pink-700"
              onClick={() => {
                setActiveReview(rv);
                setReplyText(rv.adminReply || "");
              }}
            >
              Trả lời
            </button>
          </div>
        ))}
      </div>

      {/* POPUP REPLY */}
      {activeReview && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex justify-center items-center">
          <div className="bg-white p-6 rounded-xl shadow-xl w-[400px]">
            <h3 className="font-semibold text-lg mb-3">
              Trả lời đánh giá của {activeReview.user?.name}
            </h3>

            <textarea
              value={replyText}
              onChange={(e) => setReplyText(e.target.value)}
              className="w-full p-2 border rounded"
              rows={3}
            />

            <div className="mt-4 flex justify-end gap-4">
              <button
                className="px-4 py-1 rounded bg-gray-300"
                onClick={() => setActiveReview(null)}
              >
                Hủy
              </button>

              <button
                className="px-4 py-1 bg-pink-600 text-white rounded hover:bg-pink-700"
                onClick={submitReply}
              >
                Gửi phản hồi
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminReviews;
